 11→    border-radius: 24px;
 12→    backdrop-filter: blur(16px);
 13→    -webkit-backdrop-filter: blur(16px);
 14→    box-shadow: 0 8px 24px rgba(0, 0, 0, 0.3);
 15→    z-index: 200;
 16→    white-space: nowrap;
 17→}
 18→
 19→.reaction-picker::after {
 20→    content: '';
 21→    position: absolute;
 22→    bottom: -12px;
 23→    left: 0;
 24→    right: 0;
 25→    height: 12px;
 26→}
 27→
 28→.reaction-picker-item {
 29→    background: none;
 30→    border: none;
 31→    font-size: 22px;
 32→    cursor: pointer;
 33→    padding: 4px 6px;
 34→    border-radius: 8px;
 35→    transition: background 0.15s ease;
 36→    line-height: 1;
 37→}
