 45→}
 46→
 47→/* ─── Reaction Button ─── */
 48→.reaction-button-container {
 49→    position: relative;
 50→    display: inline-flex;
 51→    align-items: center;
 52→    gap: 4px;
 53→}
 54→
 55→.reaction-button {
